import requests

BASE_URL = "http://localhost:8080"
TIMEOUT = 30

def test_api_health_endpoint():
    url = f"{BASE_URL}/api/auth/test"
    headers = {
        "Accept": "application/json"
    }
    try:
        response = requests.get(url, headers=headers, timeout=TIMEOUT)
        response.raise_for_status()
    except requests.RequestException as e:
        assert False, f"Request to /api/auth/test failed: {e}"
    try:
        json_data = response.json()
    except ValueError:
        assert False, "Response is not valid JSON"

    assert response.status_code == 200, f"Expected status code 200 but got {response.status_code}"
    assert "message" in json_data, "Response JSON does not contain 'message' key"
    assert isinstance(json_data["message"], str), "'message' value is not a string"
    assert len(json_data["message"]) > 0, "'message' value is empty"

test_api_health_endpoint()

import requests

BASE_URL = "http://localhost:8080"
LOGIN_ENDPOINT = "/api/auth/login"
TIMEOUT = 30

def test_user_login_with_invalid_credentials():
    url = BASE_URL + LOGIN_ENDPOINT
    headers = {"Content-Type": "application/json"}
    invalid_payload = {
        "username": "invalidUser123",
        "password": "wrongPassword!"
    }

    try:
        response = requests.post(url, json=invalid_payload, headers=headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"HTTP request failed: {e}"

    assert response.status_code == 401, f"Expected status code 401, got {response.status_code}"

    try:
        resp_json = response.json()
    except ValueError:
        assert False, "Response is not valid JSON"

    assert "message" in resp_json, "Response JSON does not contain 'message' field"
    assert isinstance(resp_json["message"], str) and len(resp_json["message"]) > 0, "Error message is empty or not a string"

test_user_login_with_invalid_credentials()

import requests

BASE_URL = "http://localhost:5173/8080"
LOGIN_ENDPOINT = "/api/auth/login"
TIMEOUT = 30

def test_user_login_with_deactivated_account():
    url = BASE_URL + LOGIN_ENDPOINT

    # Example credentials for a deactivated account - these must be valid in the test environment
    payload = {
        "username": "deactivated_user",
        "password": "anyPassword123!"
    }
    headers = {
        "Content-Type": "application/json"
    }

    try:
        response = requests.post(url, json=payload, headers=headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Request to {url} failed: {e}"

    assert response.status_code == 403, f"Expected status code 403, got {response.status_code}"
    try:
        resp_json = response.json()
    except ValueError:
        assert False, "Response is not a valid JSON"

    assert "message" in resp_json, "Response JSON must contain 'message'"
    # Optionally check if the message contains info about deactivated account
    assert "deactivated" in resp_json["message"].lower() or "forbidden" in resp_json["message"].lower()

test_user_login_with_deactivated_account()

import requests

BASE_URL = "http://localhost:8080"
TIMEOUT = 30

def test_fetch_current_authenticated_user_with_invalid_or_missing_token():
    url = f"{BASE_URL}/api/auth/me"
    headers_list = [
        {},  # Missing token
        {"Authorization": "Bearer invalid.token.here"}  # Invalid token
    ]

    for headers in headers_list:
        try:
            response = requests.get(url, headers=headers, timeout=TIMEOUT)
        except requests.RequestException as e:
            assert False, f"Request failed: {e}"

        assert response.status_code == 401, f"Expected 401 Unauthorized, got {response.status_code}"
        try:
            json_data = response.json()
        except ValueError:
            assert False, "Response is not in JSON format"
        assert "message" in json_data and isinstance(json_data["message"], str) and len(json_data["message"]) > 0, \
            "Response JSON does not contain a valid 'message' field"

test_fetch_current_authenticated_user_with_invalid_or_missing_token()
